from dataclasses import dataclass

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    subject_map = {}
    for triple in triples:
        if triple.subject not in subject_map:
            subject_map[triple.subject] = []
        subject_map[triple.subject].append((triple.predicate, triple.object))

    # Group triples by subject and create a single complex sentence
    sentence_parts = []

    for subject, triples in subject_map.items():
        base = f"{subject}"
        attributes = []

        for i, (predicate, obj) in enumerate(triples):
            if predicate == "cityServed":
                attributes.append(f"serves the city of {obj}")
            elif predicate == "mayor":
                attributes.append(f"has {obj} as mayor")
            elif predicate == "isPartOf":
                attributes.append(f"is part of {obj}")
            elif predicate == "operatingOrganisation":
                attributes.append(f"is operated by {obj}")
            elif predicate == "location":
                attributes.append(f"is located in {obj}")
            elif predicate == "elevationAboveTheSeaLevel" or predicate == "elevationAboveTheSeaLevelInMetres":
                # Normalize elevation to meters with 'm' suffix
                elevation = obj if obj.endswith('m') else f"{obj}m"
                attributes.append(f"has an elevation of {elevation} above sea level")
            elif predicate == "elevationAboveTheSeaLevelInFeet":
                elevation = obj if obj.endswith('feet') else f"{obj} feet"
                attributes.append(f"has an elevation of {elevation} above sea level")
            elif predicate == "runwayLength" or predicate == "1stRunwayLengthFeet" or predicate == "3rdRunwayLengthFeet":
                # Handle runway lengths with appropriate units
                if predicate == "runwayLength":
                    length = obj if obj.endswith('m') else f"{obj}m"
                    attributes.append(f"has a runway length of {length}")
                elif predicate == "1stRunwayLengthFeet":
                    length = obj if obj.endswith('feet') else f"{obj} feet"
                    attributes.append(f"has a first runway length of {length}")
                elif predicate == "3rdRunwayLengthFeet":
                    length = obj if obj.endswith('feet') else f"{obj} feet"
                    attributes.append(f"has a third runway length of {length}")
            elif predicate == "country":
                attributes.append(f"is located in {obj}")
            elif predicate == "capital":
                attributes.append(f"has {obj} as its capital")
            elif predicate == "language" or predicate == "officialLanguage":
                # Natural rephrasing: "German is the official language of Belgium"
                attributes.append(f"{obj} is the official language of {subject}")
                # Since we're rephrasing the subject, we'll handle it as a standalone clause
                base = ""  # Don't repeat subject if we're already using it in the phrase
            elif predicate == "leader":
                attributes.append(f"has {obj} as its leader")
            elif predicate == "owner":
                attributes.append(f"is owned by {obj}")
            elif predicate == "1stRunwaySurfaceType":
                if "Poaceae" in obj:
                    attributes.append(f"has a first runway surface made of {obj}, which is a type of flowering plant")
                else:
                    attributes.append(f"has a first runway surface type of {obj}")
            elif predicate == "runwaySurfaceType":
                if "Poaceae" in obj:
                    attributes.append(f"has a runway surface made of {obj}, which is a type of flowering plant")
                else:
                    attributes.append(f"has a runway surface type of {obj}")
            elif predicate == "division":
                if "Poaceae" in subject:
                    attributes.append(f"is a type of {obj}")
                else:
                    attributes.append(f"belongs to the division of {obj}")
            elif predicate == "icaoLocationIdentifier":
                attributes.append(f"has an ICAO location identifier of {obj}")
            elif predicate == "iataLocationIdentifier":
                attributes.append(f"has an IATA location identifier of {obj}")
            elif predicate == "locationIdentifier":
                attributes.append(f"has a location identifier of {obj}")
            elif predicate == "nativeName":
                attributes.append(f"has a native name of {obj}")
            elif predicate == "leaderParty":
                attributes.append(f"has a leader party of {obj}")
            elif predicate == "runwayName":
                attributes.append(f"has a runway named {obj}")
            else:
                # Fallback: use natural phrasing for unknown predicates
                attributes.append(f"has a {predicate.replace('Of', ' of')} of {obj}")

        # If base is empty (because we used "X is the official language of Y"), we don't prepend subject
        if base:
            full_part = base + " " + ", ".join(attributes)
        else:
            full_part = ", ".join(attributes)

        sentence_parts.append(full_part.strip())

    # Combine all subject groups with "which" for continuity
    result = " which ".join(sentence_parts)
    return result + "."

